async function getSignedUrlFromKey(
  Key: string,
  { isPublic, bucketName, expiresIn = 86400 }: GetUrlOptions,
): Promise<string> {
  // Already a local blob URL (e.g. from File API)
  if (Key.startsWith('blob:http')) return Key;

  // Public,  constract URL
  if (isPublic) return `https://${bucketName}.s3.nl-ams.scw.cloud/${Key}`;

  // Private, sign URL
  return s3SignedUrl(s3Client, new GetObjectCommand({ Bucket: bucketName, Key }), { expiresIn });
}

getOrgEntityCount = async ({ var: { db } }: DbContext, orgId: string, entityType: string) => {
  const key = `e:${entityType}`;
  const [row] = await db
    .select({ count: sql<number>`coalesce((${contextCountersTable.counts}->>${key})::int, 0)` })
    .from(contextCountersTable)
    .where(eq(contextCountersTable.contextKey, orgId));
  return row?.count ?? 0;
}

setCookies(_event: E, res: Response, result: APIGatewayProxyResult) {
  if (res.headers.has('set-cookie')) {
    const cookies = res.headers.getSetCookie
      ? res.headers.getSetCookie()
      : Array.from(res.headers.entries())
          .filter(([k]) => k === 'set-cookie')
          .map(([, v]) => v)

    if (Array.isArray(cookies)) {
      this.setCookiesToResult(result, cookies)
      res.headers.delete('set-cookie')
    }
  }
}

convertHeaders = (headers: Headers): CloudFrontHeaders => {
  const cfHeaders: CloudFrontHeaders = {}
  headers.forEach((value, key) => {
    cfHeaders[key.toLowerCase()] = [
      ...(cfHeaders[key.toLowerCase()] || []),
      { key: key.toLowerCase(), value },
    ]
  })
  return cfHeaders
}

findInsertBefore = (node: Node | undefined): SupportedElement | Text | undefined => {
  while (node && (node.tag === HONO_PORTAL_ELEMENT || !node.e)) {
    node = node.tag === HONO_PORTAL_ELEMENT || !node.vC?.[0] ? node.nN : node.vC[0]
  }
  return node?.e
}

parseIPv6HexCode = (code: number): number => {
  if (code >= CHAR_CODE_0 && code <= CHAR_CODE_9) {
    return code - CHAR_CODE_0
  }
  if (code >= CHAR_CODE_A && code <= CHAR_CODE_F) {
    return code - CHAR_CODE_A + 10
  }
  if (code >= CHAR_CODE_a && code <= CHAR_CODE_f) {
    return code - CHAR_CODE_a + 10
  }
  return -1
}

function base64urlDecode(str: string): string {
  // RFC 7515 §5.2: reject base64url strings with whitespace, line breaks, or invalid characters
  if (!/^[A-Za-z0-9_-]*$/.test(str)) {
    throw new Error('Invalid base64url encoding')
  }
  str = str.replace(/-/g, '+').replace(/_/g, '/')
  // Restore padding removed per RFC 7515 §2
  str += '='.repeat((4 - (str.length % 4)) % 4)
  const bytes = Uint8Array.from(atob(str), (c) => c.charCodeAt(0))
  return new TextDecoder().decode(bytes)
}

function base64urlDecodeToBytes(str: string): Uint8Array {
  if (!/^[A-Za-z0-9_-]*$/.test(str)) {
    throw new Error('Invalid base64url encoding')
  }
  str = str.replace(/-/g, '+').replace(/_/g, '/')
  str += '='.repeat((4 - (str.length % 4)) % 4)
  return Uint8Array.from(atob(str), (c) => c.charCodeAt(0))
}

getOAuthData: (c: Context): { claims: B2BTokenClaims; token: string } => {
  const claims = c.get('stytchB2BOAuthClaims')
  const token = c.get('stytchB2BOAuthToken')
  if (!claims || !token) {
    throw Error('No B2B OAuth data in context. Was B2B.authenticateOAuthToken called?')
  }
  return { claims, token }
}

function isTestFile(fsPath: string): boolean {
  return (
    fsPath.endsWith('.test.ts') ||
    fsPath.endsWith('.test.tsx') ||
    fsPath.endsWith('.test.js') ||
    fsPath.endsWith('.test.jsx') ||
    fsPath.endsWith('.spec.ts') ||
    fsPath.endsWith('.spec.tsx') ||
    fsPath.endsWith('.spec.js') ||
    fsPath.endsWith('.spec.jsx')
  )
}

function getRequestConfig(): RequestConfig {
  const cfg = getRequestSection()

  return {
    enableCodeLens: cfg.get<EnableCodeLensMode>('enableCodeLens', 'auto'),
    nodePath: (cfg.get<string>('nodePath', 'node') || 'node').trim(),
    extraArgs: cfg.get<string[]>('extraArgs', []),
  }
}

async function getQbtVersion(instance: Instance, cookie: string | null): Promise<QbtVersion> {
	const versionStr = await qbtRequestText(instance, cookie, '/app/version')
	const match = versionStr?.match(/v?(\d+)\.(\d+)\.?(\d+)?/)
	if (!match) return DEFAULT_QBT_VERSION
	return {
		major: parseInt(match[1], 10) || 4,
		minor: parseInt(match[2], 10) || 0,
		patch: parseInt(match[3], 10) || 0,
	}
}

async function getUserById(id: number): Promise<User | null> {
  const { result, error } = await redisCommand(['HGETALL', `${USER_HASH_PREFIX}${id}`])
  if (error || !result || result.length === 0) return null

  // HGETALL 返回 [key1, val1, key2, val2, ...] 格式
  const user: any = {}
  for (let i = 0; i < result.length; i += 2) {
    user[result[i]] = result[i + 1]
  }
  user.id = Number(user.id)
  return user as User
}

function cache(seconds: number) {
  return createMiddleware(async (c, next) => {
    if (!c.req.path.match(/\.[a-zA-Z0-9]+$/) || c.req.path.endsWith(".data")) {
      return next();
    }

    await next();

    if (!c.res.ok || c.res.headers.has("cache-control")) {
      return;
    }

    c.res.headers.set("cache-control", `public, max-age=${seconds}`);
  });
}

async function getInstanceStatus(): Promise<InstanceStatus> {
  const [totalRow] = await db.select({ value: count() }).from(schema.userTable);
  const [adminRow] = await db
    .select({ value: count() })
    .from(schema.userTable)
    .where(eq(schema.userTable.role, "admin"));

  return {
    hasUsers: (totalRow?.value ?? 0) > 0,
    hasAdmin: (adminRow?.value ?? 0) > 0,
  };
}

